INSERT INTO `articles` VALUES (1,1,'Как начать функциональные тренировки','Практический материал от команды НашФит: без крайностей, с понятными шагами и применимыми советами.','/demo/covers/functional.svg','training','functional-training-start','<p class=\"lead\">Как начать функциональные тренировки — это тема, в которой важна не идеальность, а последовательность. Ниже — рабочий подход, который можно применить уже сегодня.</p><h2>С чего начать</h2><p>Сначала оцените текущий уровень и выберите нагрузку, после которой остаётся ощущение контроля. Увеличивайте объём постепенно и фиксируйте изменения.</p><div class=\"article-callout article-callout--trainer\"><strong>Совет тренера Анна Волкова</strong><p>Оставляйте запас в 2–3 повторения и не меняйте сразу все привычки. Один устойчивый шаг полезнее резкого старта.</p></div><h2>Практический план</h2><ol><li>Определите одну измеримую цель на четыре недели.</li><li>Запланируйте три основных действия на неделю.</li><li>Отмечайте самочувствие, сон и уровень нагрузки.</li><li>Корректируйте план раз в неделю, а не после каждой тренировки.</li></ol><h2>Частые ошибки</h2><ul><li>Слишком быстрый рост нагрузки.</li><li>Сравнение себя с более опытными спортсменами.</li><li>Игнорирование восстановления и сна.</li><li>Отсутствие понятного плана.</li></ul><blockquote>Прогресс строится не на одном идеальном занятии, а на десятках достаточно хороших.</blockquote><h2>Что делать дальше</h2><p>Выберите подходящую бесплатную программу, сохраните статью и при необходимости запишитесь на вводную тренировку. Тренер поможет адаптировать рекомендации под ваше состояние и цели.</p>','published',0,1,5,3205,1,NULL,'2026-06-12 08:07:14','2026-06-13 23:29:45','2026-06-16 06:26:07'),(2,2,'Техника важнее веса: база силового тренинга','Практический материал от команды НашФит: без крайностей, с понятными шагами и применимыми советами.','/demo/covers/strength.svg','training','strength-technique','<p class=\"lead\">Техника важнее веса: база силового тренинга — это тема, в которой важна не идеальность, а последовательность. Ниже — рабочий подход, который можно применить уже сегодня.</p><h2>С чего начать</h2><p>Сначала оцените текущий уровень и выберите нагрузку, после которой остаётся ощущение контроля. Увеличивайте объём постепенно и фиксируйте изменения.</p><div class=\"article-callout article-callout--trainer\"><strong>Совет тренера Дмитрий Сильнов</strong><p>Оставляйте запас в 2–3 повторения и не меняйте сразу все привычки. Один устойчивый шаг полезнее резкого старта.</p></div><h2>Практический план</h2><ol><li>Определите одну измеримую цель на четыре недели.</li><li>Запланируйте три основных действия на неделю.</li><li>Отмечайте самочувствие, сон и уровень нагрузки.</li><li>Корректируйте план раз в неделю, а не после каждой тренировки.</li></ol><h2>Частые ошибки</h2><ul><li>Слишком быстрый рост нагрузки.</li><li>Сравнение себя с более опытными спортсменами.</li><li>Игнорирование восстановления и сна.</li><li>Отсутствие понятного плана.</li></ul><blockquote>Прогресс строится не на одном идеальном занятии, а на десятках достаточно хороших.</blockquote><h2>Что делать дальше</h2><p>Выберите подходящую бесплатную программу, сохраните статью и при необходимости запишитесь на вводную тренировку. Тренер поможет адаптировать рекомендации под ваше состояние и цели.</p>','published',0,1,6,3105,1,NULL,'2026-06-09 08:07:14','2026-06-13 23:29:45','2026-06-14 08:58:49'),(3,2,'Белок без мифов: сколько нужно именно вам','Практический материал от команды НашФит: без крайностей, с понятными шагами и применимыми советами.','/demo/covers/nutrition.svg','nutrition','protein-guide','<p class=\"lead\">Белок без мифов: сколько нужно именно вам — это тема, в которой важна не идеальность, а последовательность. Ниже — рабочий подход, который можно применить уже сегодня.</p><h2>С чего начать</h2><p>Сначала оцените текущий уровень и выберите нагрузку, после которой остаётся ощущение контроля. Увеличивайте объём постепенно и фиксируйте изменения.</p><div class=\"article-callout article-callout--trainer\"><strong>Совет тренера Дмитрий Сильнов</strong><p>Оставляйте запас в 2–3 повторения и не меняйте сразу все привычки. Один устойчивый шаг полезнее резкого старта.</p></div><h2>Практический план</h2><ol><li>Определите одну измеримую цель на четыре недели.</li><li>Запланируйте три основных действия на неделю.</li><li>Отмечайте самочувствие, сон и уровень нагрузки.</li><li>Корректируйте план раз в неделю, а не после каждой тренировки.</li></ol><h2>Частые ошибки</h2><ul><li>Слишком быстрый рост нагрузки.</li><li>Сравнение себя с более опытными спортсменами.</li><li>Игнорирование восстановления и сна.</li><li>Отсутствие понятного плана.</li></ul><blockquote>Прогресс строится не на одном идеальном занятии, а на десятках достаточно хороших.</blockquote><h2>Что делать дальше</h2><p>Выберите подходящую бесплатную программу, сохраните статью и при необходимости запишитесь на вводную тренировку. Тренер поможет адаптировать рекомендации под ваше состояние и цели.</p>','published',0,1,7,3010,1,NULL,'2026-06-06 08:07:14','2026-06-13 23:29:45','2026-06-16 21:53:29'),(4,1,'Что есть до и после тренировки','Практический материал от команды НашФит: без крайностей, с понятными шагами и применимыми советами.','/demo/covers/nutrition.svg','nutrition','meal-before-workout','<p class=\"lead\">Что есть до и после тренировки — это тема, в которой важна не идеальность, а последовательность. Ниже — рабочий подход, который можно применить уже сегодня.</p><h2>С чего начать</h2><p>Сначала оцените текущий уровень и выберите нагрузку, после которой остаётся ощущение контроля. Увеличивайте объём постепенно и фиксируйте изменения.</p><div class=\"article-callout article-callout--trainer\"><strong>Совет тренера Анна Волкова</strong><p>Оставляйте запас в 2–3 повторения и не меняйте сразу все привычки. Один устойчивый шаг полезнее резкого старта.</p></div><h2>Практический план</h2><ol><li>Определите одну измеримую цель на четыре недели.</li><li>Запланируйте три основных действия на неделю.</li><li>Отмечайте самочувствие, сон и уровень нагрузки.</li><li>Корректируйте план раз в неделю, а не после каждой тренировки.</li></ol><h2>Частые ошибки</h2><ul><li>Слишком быстрый рост нагрузки.</li><li>Сравнение себя с более опытными спортсменами.</li><li>Игнорирование восстановления и сна.</li><li>Отсутствие понятного плана.</li></ul><blockquote>Прогресс строится не на одном идеальном занятии, а на десятках достаточно хороших.</blockquote><h2>Что делать дальше</h2><p>Выберите подходящую бесплатную программу, сохраните статью и при необходимости запишитесь на вводную тренировку. Тренер поможет адаптировать рекомендации под ваше состояние и цели.</p>','published',0,1,8,2909,168,NULL,'2026-06-03 08:07:14','2026-06-13 23:29:45','2026-06-14 08:07:14'),(5,3,'10 минут мобильности каждый день','Практический материал от команды НашФит: без крайностей, с понятными шагами и применимыми советами.','/demo/covers/mobility.svg','recovery','mobility-daily','<p class=\"lead\">10 минут мобильности каждый день — это тема, в которой важна не идеальность, а последовательность. Ниже — рабочий подход, который можно применить уже сегодня.</p><h2>С чего начать</h2><p>Сначала оцените текущий уровень и выберите нагрузку, после которой остаётся ощущение контроля. Увеличивайте объём постепенно и фиксируйте изменения.</p><div class=\"article-callout article-callout--trainer\"><strong>Совет тренера Елена Орлова</strong><p>Оставляйте запас в 2–3 повторения и не меняйте сразу все привычки. Один устойчивый шаг полезнее резкого старта.</p></div><h2>Практический план</h2><ol><li>Определите одну измеримую цель на четыре недели.</li><li>Запланируйте три основных действия на неделю.</li><li>Отмечайте самочувствие, сон и уровень нагрузки.</li><li>Корректируйте план раз в неделю, а не после каждой тренировки.</li></ol><h2>Частые ошибки</h2><ul><li>Слишком быстрый рост нагрузки.</li><li>Сравнение себя с более опытными спортсменами.</li><li>Игнорирование восстановления и сна.</li><li>Отсутствие понятного плана.</li></ul><blockquote>Прогресс строится не на одном идеальном занятии, а на десятках достаточно хороших.</blockquote><h2>Что делать дальше</h2><p>Выберите подходящую бесплатную программу, сохраните статью и при необходимости запишитесь на вводную тренировку. Тренер поможет адаптировать рекомендации под ваше состояние и цели.</p>','published',0,1,5,2812,164,NULL,'2026-05-31 08:07:14','2026-06-13 23:29:45','2026-06-14 08:07:14'),(6,5,'Сон и восстановление: главный скрытый ресурс','Практический материал от команды НашФит: без крайностей, с понятными шагами и применимыми советами.','/demo/covers/recovery.svg','recovery','sleep-recovery','<p class=\"lead\">Сон и восстановление: главный скрытый ресурс — это тема, в которой важна не идеальность, а последовательность. Ниже — рабочий подход, который можно применить уже сегодня.</p><h2>С чего начать</h2><p>Сначала оцените текущий уровень и выберите нагрузку, после которой остаётся ощущение контроля. Увеличивайте объём постепенно и фиксируйте изменения.</p><div class=\"article-callout article-callout--trainer\"><strong>Совет тренера Софья Белова</strong><p>Оставляйте запас в 2–3 повторения и не меняйте сразу все привычки. Один устойчивый шаг полезнее резкого старта.</p></div><h2>Практический план</h2><ol><li>Определите одну измеримую цель на четыре недели.</li><li>Запланируйте три основных действия на неделю.</li><li>Отмечайте самочувствие, сон и уровень нагрузки.</li><li>Корректируйте план раз в неделю, а не после каждой тренировки.</li></ol><h2>Частые ошибки</h2><ul><li>Слишком быстрый рост нагрузки.</li><li>Сравнение себя с более опытными спортсменами.</li><li>Игнорирование восстановления и сна.</li><li>Отсутствие понятного плана.</li></ul><blockquote>Прогресс строится не на одном идеальном занятии, а на десятках достаточно хороших.</blockquote><h2>Что делать дальше</h2><p>Выберите подходящую бесплатную программу, сохраните статью и при необходимости запишитесь на вводную тренировку. Тренер поможет адаптировать рекомендации под ваше состояние и цели.</p>','published',0,1,6,2715,160,NULL,'2026-05-28 08:07:14','2026-06-13 23:29:45','2026-06-14 08:07:14'),(7,5,'Здоровая спина при сидячей работе','Практический материал от команды НашФит: без крайностей, с понятными шагами и применимыми советами.','/demo/covers/back.svg','health','healthy-back-office','<p class=\"lead\">Здоровая спина при сидячей работе — это тема, в которой важна не идеальность, а последовательность. Ниже — рабочий подход, который можно применить уже сегодня.</p><h2>С чего начать</h2><p>Сначала оцените текущий уровень и выберите нагрузку, после которой остаётся ощущение контроля. Увеличивайте объём постепенно и фиксируйте изменения.</p><div class=\"article-callout article-callout--trainer\"><strong>Совет тренера Софья Белова</strong><p>Оставляйте запас в 2–3 повторения и не меняйте сразу все привычки. Один устойчивый шаг полезнее резкого старта.</p></div><h2>Практический план</h2><ol><li>Определите одну измеримую цель на четыре недели.</li><li>Запланируйте три основных действия на неделю.</li><li>Отмечайте самочувствие, сон и уровень нагрузки.</li><li>Корректируйте план раз в неделю, а не после каждой тренировки.</li></ol><h2>Частые ошибки</h2><ul><li>Слишком быстрый рост нагрузки.</li><li>Сравнение себя с более опытными спортсменами.</li><li>Игнорирование восстановления и сна.</li><li>Отсутствие понятного плана.</li></ul><blockquote>Прогресс строится не на одном идеальном занятии, а на десятках достаточно хороших.</blockquote><h2>Что делать дальше</h2><p>Выберите подходящую бесплатную программу, сохраните статью и при необходимости запишитесь на вводную тренировку. Тренер поможет адаптировать рекомендации под ваше состояние и цели.</p>','published',0,1,7,2618,156,NULL,'2026-05-25 08:07:14','2026-06-13 23:29:45','2026-06-14 08:07:14'),(8,6,'Как подготовиться к первым 5 километрам','Практический материал от команды НашФит: без крайностей, с понятными шагами и применимыми советами.','/demo/covers/running.svg','training','first-5k','<p class=\"lead\">Как подготовиться к первым 5 километрам — это тема, в которой важна не идеальность, а последовательность. Ниже — рабочий подход, который можно применить уже сегодня.</p><h2>С чего начать</h2><p>Сначала оцените текущий уровень и выберите нагрузку, после которой остаётся ощущение контроля. Увеличивайте объём постепенно и фиксируйте изменения.</p><div class=\"article-callout article-callout--trainer\"><strong>Совет тренера Артём Лебедев</strong><p>Оставляйте запас в 2–3 повторения и не меняйте сразу все привычки. Один устойчивый шаг полезнее резкого старта.</p></div><h2>Практический план</h2><ol><li>Определите одну измеримую цель на четыре недели.</li><li>Запланируйте три основных действия на неделю.</li><li>Отмечайте самочувствие, сон и уровень нагрузки.</li><li>Корректируйте план раз в неделю, а не после каждой тренировки.</li></ol><h2>Частые ошибки</h2><ul><li>Слишком быстрый рост нагрузки.</li><li>Сравнение себя с более опытными спортсменами.</li><li>Игнорирование восстановления и сна.</li><li>Отсутствие понятного плана.</li></ul><blockquote>Прогресс строится не на одном идеальном занятии, а на десятках достаточно хороших.</blockquote><h2>Что делать дальше</h2><p>Выберите подходящую бесплатную программу, сохраните статью и при необходимости запишитесь на вводную тренировку. Тренер поможет адаптировать рекомендации под ваше состояние и цели.</p>','published',0,1,8,2521,152,NULL,'2026-05-22 08:07:14','2026-06-13 23:29:45','2026-06-14 08:07:14'),(9,4,'Почему бокс отлично развивает выносливость','Практический материал от команды НашФит: без крайностей, с понятными шагами и применимыми советами.','/demo/covers/boxing.svg','training','boxing-cardio','<p class=\"lead\">Почему бокс отлично развивает выносливость — это тема, в которой важна не идеальность, а последовательность. Ниже — рабочий подход, который можно применить уже сегодня.</p><h2>С чего начать</h2><p>Сначала оцените текущий уровень