DROP TABLE IF EXISTS `bookings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `bookings` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint unsigned DEFAULT NULL,
  `trainer_id` bigint unsigned NOT NULL,
  `trainer_service_id` bigint unsigned DEFAULT NULL,
  `payment_id` bigint unsigned DEFAULT NULL,
  `promo_code_id` bigint unsigned DEFAULT NULL,
  `promotion_id` bigint unsigned DEFAULT NULL,
  `location_id` bigint unsigned NOT NULL,
  `client_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `client_phone` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `client_comment` text COLLATE utf8mb4_unicode_ci,
  `starts_at` datetime NOT NULL,
  `ends_at` datetime NOT NULL,
  `status` enum('booked','cancelled','completed') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'booked',
  `subtotal_amount` bigint unsigned NOT NULL DEFAULT '0',
  `discount_amount` bigint unsigned NOT NULL DEFAULT '0',
  `total_amount` bigint unsigned NOT NULL DEFAULT '0',
  `payment_status` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'not_required',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `gym_location_id` bigint unsigned DEFAULT NULL,
  `price` decimal(10,2) DEFAULT NULL,
  `duration_minutes` smallint unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `bookings_user_id_foreign` (`user_id`),
  KEY `bookings_location_id_foreign` (`location_id`),
  KEY `bookings_trainer_id_starts_at_ends_at_index` (`trainer_id`,`starts_at`,`ends_at`),
  KEY `bookings_starts_at_index` (`starts_at`),
  KEY `bookings_ends_at_index` (`ends_at`),
  KEY `bookings_status_index` (`status`),
  KEY `bookings_trainer_service_id_foreign` (`trainer_service_id`),
  KEY `bookings_payment_id_foreign` (`payment_id`),
  KEY `bookings_promo_code_id_foreign` (`promo_code_id`),
  KEY `bookings_promotion_id_foreign` (`promotion_id`),
  KEY `bookings_payment_status_index` (`payment_status`),
  CONSTRAINT `bookings_location_id_foreign` FOREIGN KEY (`location_id`) REFERENCES `gym_locations` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `bookings_payment_id_foreign` FOREIGN KEY (`payment_id`) REFERENCES `payments` (`id`) ON DELETE SET NULL,
  CONSTRAINT `bookings_promo_code_id_foreign` FOREIGN KEY (`promo_code_id`) REFERENCES `promo_codes` (`id`) ON DELETE SET NULL,
  CONSTRAINT `bookings_promotion_id_foreign` FOREIGN KEY (`promotion_id`) REFERENCES `promotions` (`id`) ON DELETE SET NULL,
  CONSTRAINT `bookings_trainer_id_foreign` FOREIGN KEY (`trainer_id`) REFERENCES `trainers` (`id`) ON DELETE CASCADE,
  CONSTRAINT `bookings_trainer_service_id_foreign` FOREIGN KEY (`trainer_service_id`) REFERENCES `trainer_services` (`id`) ON DELETE SET NULL,
  CONSTRAINT `bookings_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

