CREATE TABLE `exercise_muscle` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `exercise_id` bigint unsigned NOT NULL,
  `muscle_id` bigint unsigned NOT NULL,
  `role` enum('primary','secondary') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'primary',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `exercise_muscle_exercise_id_muscle_id_unique` (`exercise_id`,`muscle_id`),
  KEY `exercise_muscle_muscle_id_role_index` (`muscle_id`,`role`),
  KEY `exercise_muscle_exercise_id_role_index` (`exercise_id`,`role`),
  CONSTRAINT `exercise_muscle_exercise_id_foreign` FOREIGN KEY (`exercise_id`) REFERENCES `exercises` (`id`) ON DELETE CASCADE,
  CONSTRAINT `exercise_muscle_muscle_id_foreign` FOREIGN KEY (`muscle_id`) REFERENCES `muscles` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=117 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
