--
-- Table structure for table `exercises`
--

DROP TABLE IF EXISTS `exercises`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `exercises` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `technique` text COLLATE utf8mb4_unicode_ci,
  `common_mistakes` text COLLATE utf8mb4_unicode_ci,
  `difficulty` enum('beginner','intermediate','advanced') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'beginner',
  `equipment` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `video_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `thumbnail_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `exercises_slug_unique` (`slug`)
) ENGINE=InnoDB AUTO_INCREMENT=49 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `exercises`
--

LOCK TABLES `exercises` WRITE;
/*!40000 ALTER TABLE `exercises` DISABLE KEYS */;
INSERT INTO `exercises` VALUES (1,'bench-press','Жим штанги лёжа','Жим штанги лёжа — упражнение для развития силы, мышечного контроля и стабильной техники. Подбирайте нагрузку под свой уровень.','Держите корпус стабильно, выполняйте движение подконтрольно и не жертвуйте техникой ради веса.','Слишком большой вес, рывки, потеря амплитуды и отсутствие контроля в негативной фазе.','intermediate','Штанга, скамья',NULL,NULL,'2026-06-14 05:03:56','2026-06-14 05:03:56'),(2,'dumbbell-bench-press','Жим гантелей лёжа','Жим гантелей лёжа — упражнение для развития силы, мышечного контроля и стабильной техники. Подбирайте нагрузку под свой уровень.','Держите корпус стабильно, выполняйте движение подконтрольно и не жертвуйте техникой ради веса.','Слишком большой вес, рывки, потеря амплитуды и отсутствие контроля в негативной фазе.','intermediate','Гантели, скамья',NULL,NULL,'2026-06-14 05:03:56','2026-06-14 05:03:56'),(3,'push-ups','Отжимания','Отжимания — упражнение для развития силы, мышечного контроля и стабильной техники. Подбирайте нагрузку под свой уровень.','Держите корпус стабильно, выполняйте движение подконтрольно и не жертвуйте техникой ради веса.','Слишком большой вес, рывки, потеря амплитуды и отсутствие контроля в негативной фазе.','beginner','Вес тела',NULL,NULL,'2026-06-14 05:03:56','2026-06-14 05:03:56'),(4,'cable-fly','Сведение рук в кроссовере','Сведение рук в кроссовере — упражнение для развития силы, мышечного контроля и стабильной техники. Подбирайте нагрузку под свой уровень.','Держите корпус стабильно, выполняйте движение подконтрольно и не жертвуйте техникой ради веса.','Слишком большой вес, рывки, потеря амплитуды и отсутствие контроля в негативной фазе.','intermediate','Кроссовер',NULL,NULL,'2026-06-14 05:03:56','2026-06-14 05:03:56'),(5,'dumbbell-fly','Разводка гантелей','Разводка гантелей — упражнение для развития силы, мышечного контроля и стабильной техники. Подбирайте нагрузку под свой уровень.','Держите корпус стабильно, выполняйте движение подконт