INSERT INTO `muscles` VALUES (1,'chest','Грудные мышцы','Pectoralis major','Грудные мышцы участвуют в жимовых движениях, приведении рук к корпусу и формируют сильный верх тела.','Приведение руки, сгибание плеча, горизонтальное сведение рук и жимовые движения.','Для роста грудных мышц нужны жимовые движения под разными углами, прогрессия нагрузки, контроль техники и стабильные лопатки.','front','2026-06-14 05:03:56','2026-06-14 05:03:56'),(2,'shoulders','Плечи / дельты','Deltoideus','Дельтовидные мышцы формируют плечевой пояс и помогают контролировать руку в разных плоскостях.','Отведение, сгибание и разгибание плеча, стабилизация плечевого сустава.','Комбинируйте жимы, махи в стороны, заднюю дельту и упражнения для стабильности лопаток.','both','2026-06-14 05:03:56','2026-06-14 05:03:56'),(3,'biceps','Бицепс','Biceps brachii','Бицепс сгибает руку в локте и участвует в супинации предплечья.','Сгибание локтя, супинация предплечья и помощь в тяговых движениях.','Используйте сгибания со штангой и гантелями, нейтральный хват и контролируемую негативную фазу.','front','2026-06-14 05:03:56','2026-06-14 05:03:56'),(4,'triceps','Трицепс','Triceps brachii','Трицепс разгибает руку в локте и сильно влияет на жимовые движения.','Разгибание локтя, стабилизация плеча и помощь во всех жимах.','Комбинируйте разгибания на блоке, французский жим, брусья и жим узким хватом.','back','2026-06-14 05:03:56','2026-06-14 05:03:56'),(5,'forearms','Предплечья','Antebrachium','Предплечья отвечают за хват, контроль кисти и устойчивость в тягах.','Сгибание и разгибание кисти, удержание веса и стабилизация хвата.','Развивайте хват через фермерскую прогулку, висы, сгибания кистей и удержания веса.','both','2026-06-14 05:03:56','2026-06-14 05:03:56'),(6,'abs','Пресс','Rectus abdominis','Прямая мышца живота помогает сгибать корпус и стабилизировать позвоночник.','Сгибание корпуса, стабилизация таза и контроль корпуса в базовых упражнениях.','Сочетайте скручивания, подъёмы ног, планки и прогрессию нагрузки без рывков поясницей.','front','2026-06-14 05:03:56','2026-06-14 05:03:56'),(7,'obliques','Косые мышцы живота','Obliquus externus et internus abdominis','Косые мышцы помогают поворачивать корпус и защищают поясницу при движениях.','Ротация и боковое сгибание корпуса, анти-ротационная стабилизация.','Используйте боковые планки, Pallof press, контролируемые повороты и переносы веса.','front','2026-06-14 05:03:56','2026-06-14 05:03:56'),(8,'lats','Широчайшие мышцы спины','Latissimus dorsi','Широчайшие формируют силу тяговых движений и V-образный силуэт.','Приведение плеча, разгибание плеча и тяга руки к корпусу.','Основа — подтягивания, тяги верхнего блока, горизонтальные тяги и контроль лопаток.','back','2026-06-14 05:03:56','2026-06-14 05:03:56'),(9,'traps','Трапеции','Trapezius','Трапеции стабилизируют лопатки, шею и верх спины.','Подъём, опускание и приведение лопаток, стабилизация плечевого пояса.','Шраги, тяги, face pull и контроль осанки помогают развить верх спины без перегруза шеи.','back','2026-06-14 05:03:56','2026-06-14 05:03:56'),(10,'lower_back','Поясница','Erector spinae','Разгибатели позвоночника помогают держать корпус и безопасно выполнять тяги.','Разгибание позвоночника, стабилизация корпуса, удержание нейтральной спины.','Начинайте с гиперэкстензии и bird-dog, затем добавляйте тяги с идеальной техникой.','back','2026-06-14 05:03:56','2026-06-14 05:03:56'),(11,'glutes','Ягодицы','Gluteus maximus / medius','Ягодичные мышцы отвечают за разгибание бедра, стабильность таза и силу нижней части тела.','Разгибание и отведение бедра, стабилизация таза, мощность в приседаниях и тягах.','Используйте хип-траст, ягодичный мост, выпады и румынскую тягу с прогрессией нагрузки.','back','2026-06-14 05:03:56','2026-06-14 05:03:56'),(12,'quads','Квадрицепсы','Quadriceps femoris','Квадрицепсы разгибают колено и дают силу в приседаниях, выпадах и жиме ногами.','Разгибание колена, стабилизация коленного сустава, работа в приседаниях.','Приседайте в контролируемой амплитуде, добавляйте жим ногами, выпады и разгибания ног.','front','2026-06-14 05:03:56','2026-06-14 05:03:56'),(13,'hamstrings','Бицепс бедра','Hamstrings','Задняя поверхность бедра сгибает колено и помогает разгибать бедро.','Сгибание колена, разгибание бедра и стабилизация таза.','Добавьте румынскую тягу, сгибания ног, становую на прямых ногах и гиперэкстензию.','back','2026-06-14 05:03:56','2026-06-14 05:03:56'),(14,'calves','Икры','Gastrocnemius / Soleus','Икроножные и камбаловидные мышцы отвечают за подъём на носки, прыжки и устойчивую походку.','Подошвенное сгибание стопы, стабилизация голеностопа, работа при беге и ходьбе.','Тренируйте икры стоя и сидя, меняйте темп, делайте паузу в верхней точке и растяжение внизу.','both','2026-06-14 05:03:56','2026-06-14 05:03:56');
/*!40000 ALTER TABLE `muscles` ENABLE KEYS */;
UNLOCK TABLES;

