INSERT INTO `products` VALUES (1,'whey-protein-pro','Сывороточный протеин Pro','Мягкий сывороточный протеин для добора белка после тренировки или в течение дня.','Сывороточный протеин Pro помогает закрыть дневную норму белка без тяжёлых перекусов. Хорошо размешивается в шейкере, подходит после силовой тренировки, утренней зарядки или как белковая добавка к каше и смузи. Вкус сделан спокойным, без приторности, чтобы продукт не надоедал при регулярном использовании.','НашФит Nutrition','NF-WHEYPROTEINP',2490.00,2890.00,41,'/demo/products/nutrition.svg','[\"/demo/products/nutrition.svg\"]','{\"Белок\": \"24 г на порцию\", \"Гарантия\": \"12 месяцев\", \"Подходит для\": \"Набор массы, восстановление, контроль питания\", \"Когда принимать\": \"После тренировки или между приёмами пищи\"}','[\"Выбор тренера\", \"Для восстановления\"]',1,'2026-06-13 23:29:44','2026-06-14 08:07:10',1,1,1,0,1,180),(2,'creatine-mono','Креатин моногидрат','Классический креатин моногидрат для силового прогресса и работы в подходах.','Креатин моногидрат — базовая добавка для тех, кто работает над силой, мощностью и объёмом тренировок. Его удобно принимать ежедневно: без сложных схем загрузки, просто в воде, соке или вместе с протеином. Подходит для тренажёрного зала, функционального тренинга и домашних силовых занятий.','НашФит Nutrition','NF-CREATINEMONO',1290.00,NULL,36,'/demo/products/nutrition.svg','[\"/demo/products/nutrition.svg\"]','{\"Цель\": \"Сила, мощность, рабочий объём\", \"Порция\": \"3–5 г в день\", \"Формат\": \"Порошок без сахара\", \"Гарантия\": \"12 месяцев\"}','[\"Силовая база\"]',1,'2026-06-13 23:29:44','2026-06-14 08:07:10',1,0,0,0,1,175),(3,'protein-bars-box','Протеиновые батончики, 12 шт.','Коробка белковых батончиков для перекуса после тренировки, работы или дороги.','Протеиновые батончики удобно держать в сумке, шкафчике или машине. Они помогают не срываться на случайные сладости, когда между приёмами пищи большой перерыв. Текстура плотная, вкус десертный, но состав рассчитан на фитнес-режим: больше белка, понятная калорийность и удобная порция.','НашФит Nutrition','NF-PROTEINBARSB',1690.00,NULL,31,'/demo/products/nutrition.svg','[\"/demo/products/nutrition.svg\"]','{\"Формат\": \"Готовый перекус\", \"Гарантия\": \"12 месяцев\", \"В коробке\": \"12 батончиков\", \"Подходит для\": \"Работа, дорога, после тренировки\"}','[\"Удобный перекус\"]',1,'2026-06-13 23:29:44','2026-06-14 08:07:10',1,0,0,0,1,170),(4,'preworkout-focus','Предтренировочный комплекс Focus','Предтренировочный комплекс для концентрации и бодрого старта занятия.','Focus помогает собраться перед тренировкой, когда день был длинным, а занятие пропускать не хочется. Формула рассчитана на ощущение бодрости без перегруженного вкуса. Подойдёт для силовых, интервальных и беговых тренировок, где важны концентрация, темп и рабочее настроение.','НашФит Nutrition','NF-PREWORKOUTFO',1890.00,2290.00,23,'/demo/products/nutrition.svg','[\"/demo/products/nutrition.svg\"]','{\"Цель\": \"Энергия, фокус, темп\", \"Формат\": \"Порошок для напитка\", \"Гарантия\": \"12 месяцев\", \"Когда принимать\": \"За 20–30 минут до тренировки\"}','[\"Перед тренировкой\"]',1,'2026-06-13 23:29:44','2026-06-14 08:07:10',1,0,0,0,1,165),(5,'magnesium-recovery','Магний Recovery','Магний для вечернего восстановления, режима сна и расслабления мышц.','Магний Recovery подходит тем, кто тренируется регулярно и хочет лучше восстанавливаться между занятиями. Его удобно добавить в вечерний ритуал: после душа, растяжки или лёгкой прогулки. Добавка не заменяет сон и питание, но помогает поддерживать спокойный режим восстановления.','НашФит Recovery','NF-MAGNESIUMREC',890.00,NULL,24,'/demo/products/recovery.svg','[\"/demo/products/recovery.svg\"]','{\"Цель\": \"Восстановление и режим\", \"Формат\": \"60 капсул\", \"Гарантия\": \"12 месяцев\", \"Когда принимать\": \"Вечером или по рекомендации специалиста\"}','[\"Восстановление\"]',3,'2026-06-13 23:29:44','2026-06-14 08:07:10',1,0,1,0,1,160),(6,'foam-roller','Массажный ролл','Плотный массажный ролл для разминки, заминки и работы с зажатостью.','Массажный ролл помогает подготовить мышцы к нагрузке и мягко снять напряжение после тренировки. Его используют для икр, бёдер, спины, широчайших и ягодичных мышц. Поверхность достаточно плотная для заметного эффекта, но без чрезмерной жёсткости для новичков.','НашФит Recovery','NF-FOAMROLLER',1690.00,NULL,28,'/demo/products/recovery.svg','[\"/demo/products/recovery.svg\"]','{\"Длина\": \"Универсальная\", \"Гарантия\": \"12 месяцев\", \"Жёсткость\": \"Средняя\", \"Подходит для\": \"Разминка, заминка, мобильность\"}','[\"Для заминки\"]',3,'2026-06-13 23:29:44','2026-06-14 08:07:10',1,1,0,0,1,155),(7,'massage-gun-mini','Массажный пистолет Mini','Компактный массажный пистолет для восстановления после зала и рабочего дня.','Mini легко брать с собой в зал или поездку. Он помогает быстро пройтись по напряжённым зонам после силовой тренировки, бега или долгого сидения. Несколько насадок позволяют работать с крупными мышцами и более точечно — с зонами, где нужна аккуратность.','НашФит Recovery','NF-MASSAGEGUNMI',5990.00,6390.00,7,'/demo/products/recovery.svg','[\"/demo/products/recovery.svg\"]','{\"Формат\": \"Компактный\", \"Насадки\": \"Для разных зон\", \"Гарантия\": \"12 месяцев\", \"Подходит для\": \"После тренировки и дороги\"}','[\"Компактный\"]',3,'2026-06-13 23:29:44','2026-06-14 08:07:10',0,0,0,0,1,150),(8,'resistance-bands-set','Набор фитнес-резинок','Набор резинок разного сопротивления для ягодиц, плеч, спины и разминки.','Фитнес-резинки подходят для домашних тренировок, активации мышц перед залом и добивочных упражнений. В наборе несколько уровней сопротивления: можно начать мягко и постепенно усложнять нагрузку. Особенно полезны для ягодичных, плечевого пояса, осанки и работы над техникой.','НашФит Gear','NF-RESISTANCEBA',1490.00,NULL,43,'/demo/products/equipment.svg','[\"/demo/products/equipment.svg\"]','{\"В наборе\": \"3 уровня сопротивления\", \"Гарантия\": \"12 месяцев\", \"Материал\": \"Эластичный латекс\", \"Подходит для\": \"Дом, зал, разминка\"}','[\"Для дома\", \"Популярно\"]',2,'2026-06-13 23:29:44','2026-06-14 08:07:10',0,0,0,1,1,145),(9,'adjustable-dumbbell','Разборная гантель','Разборная гантель для домашней силовой тренировки без лишнего инвентаря.','Разборная гантель заменяет сразу несколько фиксированных весов и экономит место дома. Подходит для жима, тяг, выпадов, приседаний, подъёмов на бицепс и упражнений на плечи. Вес можно подбирать под упражнение и уровень, а не ограничиваться одним вариантом нагрузки.','НашФит Gear','NF-ADJUSTABLEDU',4490.00,NULL,18,'/demo/products/equipment.svg','[\"/demo/products/equipment.svg\"]','{\"Тип\": \"Разборная\", \"Гарантия\": \"12 месяцев\", \"Подходит для\": \"Силовые тренировки дома\", \"Преимущество\": \"Экономит место\"}','[\"Домашняя сила\"]',2,'2026-06-13 23:29:44','2026-06-14 08:07:10',0,0,1,1,1,140),(10,'kettlebell-home','Гиря для дома','Гиря для функциональных упражнений, силы хвата и выносливости.','Гиря подходит для махов, приседаний, тяг, жимов и переносок. Это универсальный инструмент для тренировок всего тела: можно развивать силу, координацию и кардио-нагрузку в одном комплексе. Хороший вариант для тех, кто хочет больше динамики, чем с обычными гантелями.','НашФит Gear','NF-KETTLEBELLHO',2490.00,2890.00,23,'/demo/products/equipment.svg','[\"/demo/products/equipment.svg\"]','{\"Цель\": \"Функциональная сила\", \"Гарантия\": \"12 месяцев\", \"Покрытие\": \"Матовая поверхность\", \"Подходит для\": \"Дом и зал\"}','[\"Функционально\"]',2,'2026-06-13 23:29:45','2026-06-14 08:07:10',0,0,0,1,1,135),(11,'yoga-strap','Ремень для йоги','Ремень для йоги и растяжки, чтобы безопасно углублять амплитуду.','Ремень помогает выполнять наклоны, раскрытие плеч, растяжку задней поверхности бедра и упражнения на мобильность без рывков. Он особенно полезен новичкам: позволяет держать правильное положение и постепенно увеличивать амплитуду без давления на суставы.','НашФит Gear','NF-YOGASTRAP',690.00,NULL,30,'/demo/products/home.svg','[\"/demo/products/home.svg\"]','{\"Цель\": \"Растяжка и мобильность\", \"Длина\": \"Универсальная\", \"Гарантия\": \"12 месяцев\", \"Подходит для\": \"Йога, пилатес, восстановление\"}','[\"Для йоги\"]',5,'2026-06-13 23:29:45','2026-06-14 08:07:10',0,1,0,1,1,130),(12,'fitness-mat-pro','Коврик для фитнеса Pro','Плотный коврик для силовых, йоги, растяжки и тренировок дома.','Коврик Pro не скользит на базовых упражнениях и даёт комфортную опору для коленей, локтей и спины. Подходит для утренней зарядки, йоги, пилатеса, упражнений на пресс и домашних силовых комплексов. Легко сворачивается и не занимает много места.','НашФит Gear','NF-FITNESSMATPR',2790.00,NULL,19,'/demo/products/home.svg','[\"/demo/products/home.svg\"]','{\"Уход\": \"Легко протирается\", \"Гарантия\": \"12 месяцев\", \"Назначение\": \"Йога, фитнес, пресс\", \"Поверхность\": \"Нескользящая\"}','[\"Для дома\"]',5,'2026-06-13 23:29:45','2026-06-14 08:07:10',0,0,0,1,1,125),(13,'ankle-weights','Утяжелители для ног','Утяжелители для ног и рук, чтобы добавить нагрузку в домашние упражнения.','Утяжелители помогают усложнить махи, подъёмы ног, ягодичные упражнения и лёгкие кардио-комплексы. Мягкая фиксация держится уверенно, а вес распределяется комфортно. Хороший способ прогрессировать дома, когда обычные упражнения стали слишком лёгкими.','НашФит Gear','NF-ANKLEWEIGHTS',1990.00,2390.00,20,'/demo/products/home.svg','[\"/demo/products/home.svg\"]','{\"Цель\": \"Тонус и усложнение упражнений\", \"Гарантия\": \"12 месяцев\", \"Крепление\": \"Липучка\", \"Использование\": \"Ноги и руки\"}','[\"Тонус\"]',5,'2026-06-13 23:29:45','2026-06-14 08:07:10',0,0,1,1,1,120),(14,'training-gloves','Перчатки для тренировок','Перчатки для хвата, защиты ладоней и уверенной работы с весами.','Перчатки помогают держать гриф, гантели и рукояти тренажёров увереннее, особенно при высокой влажности или большом объёме подходов. Ладони меньше натираются, а кисть ощущает более стабильную опору. Подойдут для силовых тренировок и функциональных комплексов.','НашФит Gear','NF-TRAININGGLOV',1390.00,NULL,32,'/demo/products/apparel.svg','[\"/demo/products/apparel.svg\"]','{\"Гарантия\": \"12 месяцев\", \"Материал\": \"Дышащая ткань\", \"Назначение\": \"Хват и защита ладоней\", \"Подходит для\": \"Тренажёры, гантели, турник\"}','[\"Для хвата\"]',4,'2026-06-13 23:29:45','2026-06-14 08:07:10',0,0,0,0,1,115),(15,'gym-bag-city','Спортивная сумка City','Спортивная сумка для формы, обуви, шейкера и вещей на день.','City — это сумка для тех, кто совмещает зал, работу и городские дела. Внутри достаточно места для формы, полотенца, бутылки и аксессуаров. Отдельные зоны помогают не смешивать чистые вещи и тренировочный инвентарь, а плотные ручки удобны для ежедневного использования.','НашФит','NF-GYMBAGCITY',3490.00,NULL,15,'/demo/products/apparel.svg','[\"/demo/products/apparel.svg\"]','{\"Формат\": \"Город + зал\", \"Гарантия\": \"12 месяцев\", \"Отделения\": \"Для формы и аксессуаров\", \"Подходит для\": \"Ежедневные тренировки\"}','[\"Для зала\"]',4,'2026-06-13 23:29:45','2026-06-14 08:07:10',0,0,0,0,1,110),(16,'heart-rate-monitor','Нагрудный пульсометр','Нагрудный пульсометр для контроля интенсивности и кардио-прогресса.','Пульсометр помогает тренироваться не на ощущениях, а по понятным зонам нагрузки. Он полезен для бега, интервальных занятий, снижения веса и восстановления: можно видеть, когда стоит прибавить, а когда лучше снизить темп. Подходит новичкам и опытным любителям кардио.','НашФит Tech','NF-HEARTRATEMON',5490.00,5890.00,8,'/demo/products/equipment.svg','[\"/demo/products/equipment.svg\"]','{\"Тип\": \"Нагрудный датчик\", \"Цель\": \"Контроль пульса\", \"Гарантия\": \"12 месяцев\", \"Подходит для\": \"Бег, HIIT, кардио\"}','[\"Кардио-контроль\"]',2,'2026-06-13 23:29:45','2026-06-14 08:07:10',0,1,0,1,1,105),(17,'whey-protein-gold-standard','Whey Protein Gold Standard','Сывороточный протеин для добора белка после тренировки и в течение дня.','Сывороточный протеин премиум-класса. 24 г белка на порцию, быстрое усвоение, мягкая текстура и удобные варианты вкуса.','NashFit','NF-WHEY-GS',4990.00,5490.00,40,'/seed-images/products/whey-protein-gold-standard/main.webp','[\"/seed-images/products/whey-protein-gold-standard/main.webp\", \"/seed-images/products/whey-protein-gold-standard/variant-vanilla-2kg.webp\"]','{\"Цель\": \"набор белка и восстановление\", \"Белок\": \"24 г на порцию\", \"Вкусы\": \"Chocolate / Vanilla\", \"Формат\": \"порошок\"}','[\"Хит\", \"Для силы\", \"Проверено тренерами\"]',6,'2026-06-14 07:10:13','2026-06-17 17:15:54',1,0,1,1,1,2),(18,'casein-protein','Casein Protein','Казеин для медленного высвобождения аминокислот и ночного восстановления.','Казеиновый протеин для вечернего приёма. Помогает закрыть белок на ночь и поддержать восстановление после нагрузки.','NashFit','NF-CASEIN',4490.00,4990.00,30,'/seed-images/products/casein-protein/main.webp','[\"/seed-images/products/casein-protein/main.webp\", \"/seed-images/products/casein-protein/lifestyle.webp\"]','{\"Тип\": \"мицеллярный казеин\", \"Вкус\": \"Vanilla\", \"Цель\": \"ночное восстановление\"}','[\"Восстановление\", \"Перед сном\"]',6,'2026-06-14 07:10:13','2026-06-16 21:18:10',1,0,1,1,1,0),(19,'mass-gainer-pro','Mass Gainer Pro','Высококалорийный гейнер для набора массы и восстановления энергии.','Гейнер для атлетов, которым сложно добирать калории. Содержит белки и углеводы для роста массы и восстановления.','NashFit','NF-GAINER-PRO',5490.00,5990.00,25,'/seed-images/products/mass-gainer-pro/main.webp','[\"/seed-images/products/mass-gainer-pro/main.webp\", \"/seed-images/products/mass-gainer-pro/lifestyle.webp\"]','{\"Вкус\": \"Chocolate\", \"Белок\": \"50 г\", \"Калорийность\": \"1250 ккал на порцию\"}','[\"Масса\", \"1250 ккал\"]',7,'2026-06-14 07:10:13','2026-06-16 21:18:11',1,0,1,0,1,0),(20,'bcaa-5000','BCAA 5000','BCAA для восстановления, выносливости и поддержки мышц во время нагрузки.','Аминокислоты с разветвлённой цепью. 5 г на порцию, яркий вкус и удобный формат для тренировки.','NashFit','NF-BCAA-5000',2490.00,2790.00,100,'/seed-images/products/bcaa-5000/main.webp','[\"/seed-images/products/bcaa-5000/main.webp\", \"/seed-images/products/bcaa-5000/lifestyle.webp\"]','{\"BCAA\": \"5 г\", \"Вкус\": \"Berry Blast / Fruit Punch\", \"Цель\": \"восстановление\"}','[\"Для тренировки\", \"В наличии\"]',8,'2026-06-14 07:10:13','2026-06-14 07:10:13',1,1,1,1,1,0),(21,'l-glutamine','L-Glutamine','Глютамин для восстановления после интенсивных тренировок.','Глютамин 5 г на порцию. Подходит для восстановления, поддержки иммунитета и режима после тяжёлых тренировок.','NashFit','NF-GLUTAMINE',1990.00,2290.00,80,'/seed-images/products/l-glutamine/main.webp','[\"/seed-images/products/l-glutamine/main.webp\", \"/seed-images/products/l-glutamine/lifestyle.webp\"]','{\"Вкус\": \"Unflavored\", \"Порция\": \"5 г\", \"Формат\": \"порошок\"}','[\"Восстановление\", \"Без вкуса\"]',8,'2026-06-14 07:10:13','2026-06-16 21:18:11',0,0,1,1,1,0),(22,'omega-3-ultra','Omega-3 Ultra','Омега-3 высокой концентрации для сердца, суставов и общего здоровья.','Рыбий жир высокой концентрации. Поддерживает сердце, сосуды и суставы в период регулярных тренировок.','NashFit','NF-OMEGA-3',1490.00,1690.00,150,'/seed-images/products/omega-3-ultra/main.webp','[\"/seed-images/products/omega-3-ultra/main.webp\", \"/seed-images/products/omega-3-ultra/lifestyle.webp\"]','{\"Формат\": \"softgels\", \"Дозировка\": \"1000 мг\", \"Количество\": \"120 капсул\"}','[\"Здоровье\", \"Суставы\"]',9,'2026-06-14 07:10:13','2026-06-16 21:18:11',0,0,0,1,1,0),(23,'multivitamin-sport','Multivitamin Sport','Комплекс витаминов и минералов для активных людей.','Ежедневная поддержка энергии, иммунитета и общего самочувствия при регулярных тренировках.','NashFit','NF-MULTI-SPORT',1790.00,1990.00,119,'/seed-images/products/multivitamin-sport/main.webp','[\"/seed-images/products/multivitamin-sport/main.webp\", \"/seed-images/products/multivitamin-sport/lifestyle.webp\"]','{\"Порций\": \"30\", \"Формат\": \"таблетки / капсулы\", \"Поддержка\": \"энергия, иммунитет, восстановление\"}','[\"Ежедневно\", \"Витамины\"]',9,'2026-06-14 07:10:13','2026-06-17 20:03:57',1,1,0,1,1,0),(24,'rezinovyy-espander','Резиновый эспандер','Набор эспандеров разной жёсткости для дома, зала и разминки.','Комплект эспандеров с несколькими уровнями сопротивления, ручками, креплением и сумкой для хранения.','NashFit','NF-BANDS-SET',990.00,1290.00,199,'/seed-images/products/rezinovyy-espander/main.webp','[\"/seed-images/products/rezinovyy-espander/main.webp\", \"/seed-images/products/rezinovyy-espander/lifestyle.webp\"]','{\"Уровни\": \"10–50 lbs\", \"Комплект\": \"ленты, ручки, крепление, мешок\", \"Назначение\": \"домашние тренировки\"}','[\"Дом\", \"Инвентарь\"]',2,'2026-06-14 07:10:13','2026-06-17 19:41:46',1,0,1,1,1,0),(25,'kovrik-dlya-yogi','Коврик для йоги','Противоскользящий коврик 6 мм для йоги, растяжки и домашней практики.','Плотный коврик с текстурной поверхностью, ремнём для переноски и спокойным премиальным дизайном.','NashFit','NF-YOGA-MAT',2490.00,2790.00,58,'/seed-images/products/kovrik-dlya-yogi/main.webp','[\"/seed-images/products/kovrik-dlya-yogi/main.webp\", \"/seed-images/products/kovrik-dlya-yogi/lifestyle.webp\"]','{\"Цвета\": \"sage / charcoal\", \"Толщина\": \"6 мм\", \"Поверхность\": \"anti-slip\"}','[\"Йога\", \"Anti-slip\"]',2,'2026-06-14 07:10:13','2026-06-17 19:03:47',1,0,0,1,1,6),(26,'butylka-dlya-vody-1l','Бутылка для воды 1л','Спортивная бутылка 1 л с мерной шкалой и герметичной крышкой.','BPA-free бутылка для тренировок с удобной шкалой, ремешком и надёжной крышкой.','NashFit','NF-WATER-BOTTLE-1L',590.00,790.00,300,'/seed-images/products/butylka-dlya-vody-1l/main.webp','[\"/seed-images/products/butylka-dlya-vody-1l/main.webp\", \"/seed-images/products/butylka-dlya-vody-1l/lifestyle.webp\"]','{\"Объём\": \"1 л\", \"Шкала\": \"ml / oz\", \"Материал\": \"BPA-free пластик\"}','[\"BPA-free\", \"1 литр\"]',2,'2026-06-14 07:10:13','2026-06-