INSERT INTO `programs` VALUES (1,1,'Функциональный старт','Четырёхнедельный вход в тренировки без перегруза: техника базовых движений, лёгкие круги, кор и привычка заниматься регулярно. Подходит тем, кто возвращается после перерыва или начинает с нуля.','Начальный',4,0.00,'/seed-images/programs/funktsionalnyy-start.png','2026-06-13 23:29:45','2026-06-17 22:36:07'),(2,2,'Сильное тело','Силовая программа на восемь недель: ноги, спина, грудь, плечи и корпус. Внутри — прогрессия рабочих весов, контроль техники и разгрузочные акценты, чтобы сила росла без хаоса.','Средний',8,0.00,'/seed-images/programs/moshch-i-sila.png','2026-06-13 23:29:45','2026-06-17 22:36:07'),(3,2,'Основа набора массы','Десятинедельный план гипертрофии для тех, кто хочет набрать мышечную массу системно: прогрессия объёма, работа в целевых повторениях, питание и восстановление без случайных тренировок.','Средний',10,0.00,'/seed-images/programs/silovaya-baza.png','2026-06-13 23:29:45','2026-06-17 22:36:07'),(4,1,'Умное снижение веса','Программа для снижения веса без наказаний: силовые основы, низкоударное кардио, шаги, питание и восстановление. Цель — расход энергии, тонус и привычки, которые реально выдержать.','Начальный',8,0.00,'/demo/covers/weight-loss.svg','2026-06-13 23:29:45','2026-06-13 23:56:16'),(5,3,'Перезагрузка мобильности','Шестинедельный план для тех, кто чувствует скованность в плечах, тазобедренных и спине. Программа сочетает мягкую силу, дыхание, контроль амплитуды и короткие домашние задания.','Начальный',6,0.00,'/demo/covers/mobility.svg','2026-06-13 23:29:45','2026-06-13 23:56:16'),(6,14,'Утренняя йога','Короткая утренняя практика на четыре недели: дыхание, мягкая мобилизация, баланс и спокойное включение тела. Подходит для дома и не требует сложных асан.','Начальный',4,0.00,'/demo/covers/yoga.svg','2026-06-13 23:29:45','2026-06-13 23:56:16'),(7,4,'Основы бокса','Бокс для новичков без спаррингов: стойка, передвижения, базовые удары, координация и кардио. Программа развивает выносливость и уверенность в движении.','Начальный',6,0.00,'/demo/covers/boxing.svg','2026-06-13 23:29:45','2026-06-13 23:56:16'),(8,11,'Здоровая спина','Бережная программа для укрепления спины, корпуса и ягодичных. Без резких движений: учимся разгружать поясницу, включать лопатки и строить устойчивую осанку.','Начальный',6,0.00,'/demo/covers/back.svg','2026-06-13 23:29:45','2026-06-13 23:56:17'),(9,6,'Первые 5 километров','Восьминедельный путь к первым пяти километрам: чередование бега и ходьбы, силовая профилактика травм, пульсовой контроль и понятная прогрессия.','Начальный',8,0.00,'/demo/covers/running.svg','2026-06-13 23:29:45','2026-06-13 23:56:17'),(10,7,'Сильный корпус','Программа для мышц корпуса без бесконечных скручиваний: антискручивание, стабилизация, переноски, баланс и контроль таза. Подходит как дополнение к силовым тренировкам.','Средний',6,0.00,'/demo/covers/core.svg','2026-06-13 23:29:45','2026-06-13 23:56:18'),(11,13,'Сила дома','Домашняя силовая программа с гантелями, резинками и собственным весом. План построен так, чтобы прогрессировать даже без большого зала: темп, паузы, односторонняя работа и плотность.','Средний',8,0.00,'/demo/covers/home.svg','2026-06-13 23:29:45','2026-06-13 23:56:18'),(12,5,'Неделя восстановления','Короткая программа для разгрузки после тяжёлого цикла, стресса или перерыва. Внутри — мягкая мобильность, лёгкая активность, дыхание и восстановление без ощущения простоя.','Начальный',2,0.00,'/demo/covers/recovery.svg','2026-06-13 23:29:45','2026-06-13 23:56:18');
