/*!40000 ALTER TABLE `trainers` DISABLE KEYS */;
INSERT INTO `trainers` VALUES (1,1,'Анна Волкова','Функциональный тренинг и снижение веса',7,31,'Помогает начать тренироваться без перегрузки, выстроить привычку и улучшить композицию тела.','/demo/trainers/anna-volkova.svg',NULL,'@anna_volkova_nashfit','+79990001001','2026-06-13 23:29:42','2026-06-13 23:29:42'),(2,2,'Дмитрий Сильнов','Бодибилдинг и набор мышечной массы',10,35,'Специалист по силовой подготовке, гипертрофии и безопасной технике базовых упражнений.','/demo/trainers/dmitry-silnov.svg',NULL,'@dmitry_silnov_nashfit','+79990001002','2026-06-13 23:29:42','2026-06-13 23:29:42'),(3,3,'Елена Орлова','Йога, растяжка и мобильность',9,34,'Развивает мобильность, баланс и контроль тела. Практики подходят новичкам и опытным спортсменам.','/demo/trainers/elena-orlova.svg',NULL,'@elena_orlova_nashfit','+79990001003','2026-06-13 23:29:42','2026-06-13 23:29:42'),(4,4,'Максим Романов','Бокс и функциональная выносливость',8,33,'Тренировки с элементами бокса, координации и интервальной нагрузки для яркого прогресса.','/demo/trainers/maksim-romanov.svg',NULL,'@maksim_romanov_nashfit','+79990001004','2026-06-13 23:29:42','2026-06-13 23:29:42'),(5,5,'Софья Белова','Восстановление и здоровая спина',11,38,'Помогает вернуться к активности после перерывов и уменьшить дискомфорт через корректное движение.','/demo/trainers/sofia-belova.svg',NULL,'@sofia_belova_nashfit','+79990001005','2026-06-13 23:29:43','2026-06-13 23:29:43'),(6,6,'Артём Лебедев','Бег и развитие выносливости',6,29,'Готовит к первым 5 и 10 километрам, учит распределять нагрузку и бегать без травм.','/demo/trainers/artem-lebedev.svg',NULL,'@artem_lebedev_nashfit','+79990001006','2026-06-13 23:29:43','2026-06-13 23:29:43'),(7,7,'Виктория Морозова','Пилатес и тренировки для женщин',8,32,'Фокус на осанке, мышцах корпуса и бережном укреплении всего тела.','/demo/trainers/victoria-morozova.svg',NULL,'@victoria_morozova_nashfit','+79990001007','2026-06-13 23:29:43','2026-06-13 23:29:43'),(8,8,'Илья Ковалёв','Пауэрлифтинг и силовая подготовка',12,39,'Ставит технику приседа, жима и тяги, помогает системно увеличивать силовые показатели.','/demo/trainers/ilya-kovalev.svg',NULL,'@ilya_kovalev_nashfit','+79990001008','2026-06-13 23:29:43','2026-06-13 23:29:43'),(9,16,'Кирилл Савин','HIIT, кросс-тренинг и жиросжигание',7,30,'Собирает динамичные тренировки с понятной прогрессией: без хаоса, но с высокой отдачей по выносливости и тонусу.','/demo/trainers/kirill-savin.svg',NULL,'@kirill_savin_nashfit','+79990001009','2026-06-13 23:56:11','2026-06-13 23:56:11'),(10,17,'Марина Устинова','Нутрициология и коррекция привычек',9,36,'Помогает выстроить питание без запретов: режим, белок, порции, перекусы и поддержка тренировочных целей.','/demo/trainers/marina-ustinova.svg',NULL,'@marina_ustinova_nashfit','+79990001010','2026-06-13 23:56:11','2026-06-13 23:56:11'),(11,18,'Роман Шаталов','Реабилитационный фитнес и суставная мобильность',13,41,'Работает с бережным возвращением к нагрузкам, укреплением слабых звеньев и контролем техники движения.','/demo/trainers/roman-shatalov.svg',NULL,'@roman_shatalov_nashfit','+79990001011','2026-06-13 23:56:12','2026-06-13 23:56:12'),(12,19,'Алиса Корнеева','Групповые программы, танцевальное кардио и тонус',6,28,'Делает тренировки эмоциональными и понятными: ритм, координация, корпус и безопасная кардио-нагрузка.','/demo/trainers/alisa-korneeva.svg',NULL,'@alisa_korneeva_nashfit','+79990001012','2026-06-13 23:56:12','2026-06-13 23:56:12'),(13,20,'Павел Денисов','Тяжёлая атлетика и техника сложных движений',14,40,'Разбирает рывковые, тяговые и силовые паттерны на понятные шаги, чтобы прогресс шёл без лишнего риска.','/demo/trainers/pavel-denisov.svg',NULL,'@pavel_denisov_nashfit','+79990001013','2026-06-13 23:56:12','2026-06-13 23:56:12'),(14,21,'Наталья Жукова','Йога-терапия, дыхание и восстановление',12,37,'Соединяет мягкую силовую работу, дыхание и мобильность для снижения напряжения и лучшего самочувствия.','/demo/trainers/natalia-zhukova.svg',NULL,'@natalia_zhukova_nashfit','+79990001014','2026-06-13 23:56:12','2026-06-13 23:56:12'),(15,23,'Анна Кузнецова','Функциональный тренинг',7,28,'Специалист по функциональному тренингу и безопасному снижению веса. Помогает укрепить корпус, улучшить выносливость и выстроить комфортный режим тренировок.','/seed-images/trainers/anna-kuznetsova.webp',NULL,'@anna_nashfit_vk','+79990000002','2026-06-14 07:10:12','2026-06-14 11:56:23'),(16,24,'Дмитрий Сильнов','Силовая подготовка',10,35,'Тренер по силовой подготовке и технике базовых движений. Помогает набрать мышечную массу и повысить силовые показатели без лишнего риска.','/seed-images/trainers/dmitry-silnov.webp',NULL,'@dmitry_strength_vk','+79990000003','2026-06-14 07:10:12','2026-06-14 11:56:23'),(17,25,'Елена Фитнесова','Йога и стретчинг',5,26,'Инструктор по йоге и растяжке. Помогает развить гибкость, снять напряжение и восстановить подвижность после тренировок.','/seed-images/trainers/elena-fitnessova.webp',NULL,'@elena_yoga_vk','+79990000004','2026-06-14 07:10:12','2026-06-14 07:10:12'),(18,27,'София Морозова','Женский фитнес и mobility',6,29,'Работает с женским фитнесом, мобильностью и мягкой коррекцией осанки. Помогает улучшить тонус тела, координацию и качество движения.','/seed-images/trainers/sofia-morozova.webp',NULL,'@sofia_move_vk','+79990000005','2026-06-14 11:56:24','2026-06-14 11:56:24'),(19,28,'Павел Орлов','Набор мышечной массы',9,33,'Тренер по набору мышечной массы и классическому бодибилдингу. Составляет прогрессирующие планы тренировок и питания под цель.','/seed-images/trainers/pavel-orlov.webp',NULL,'@pavel_mass_vk','+79990000006','2026-06-14 11:56:24','2026-06-14 11:56:24'),(20,29,'Алина Ветрова','Пилатес и stretch',5,27,'Ведёт занятия по пилатесу, стретчингу и мягкому восстановлению. Помогает снять зажимы, улучшить гибкость и самочувствие.','/seed-images/trainers/alina-vetrova.webp',NULL,'@alina_stretch_vk','+79990000007','2026-06-14 11:56:24','2026-06-14 11:56:24'),(21,30,'Роман Белов','Cross-training',8,31,'Тренер по интервальным и кросс-тренировкам. Помогает развить общую физическую форму, выносливость и функциональную силу.','/seed-images/trainers/roman-belov.webp',NULL,'@roman_cross_vk','+79990000008','2026-06-14 11:56:24','2026-06-14 11:56:24'),(22,31,'Максим Козлов','Единоборства и кондиция',7,30,'Тренер по боксу, кардио-кондиции и координации. Подходит тем, кто хочет сочетать мощную тренировку, технику и выносливость.','/seed-images/trainers/maksim-kozlov.webp',NULL,'@maksim_box_vk','+79990000009','2026-06-14 11:56:25','2026-06-14 11:56:25'),(23,32,'Андрей Соколов','TRX и функциональная сила',11,39,'Эксперт по TRX, функциональной силе и тренировкам для занятых людей. Умеет быстро собрать эффективную программу под график клиента.','/seed-images/trainers/andrey-sokolov.webp',NULL,'@andrey_trx_vk','+79990000015','2026-06-14 11:56:25','2026-06-14 11:56:25'),(24,33,'Ксения Романова','Фитнес для начинающих',4,26,'Помогает новичкам без стресса войти в тренировки, освоить технику и удерживать мотивацию. Специализируется на мягком старте и дисциплине.','/seed-images/trainers/ksenia-romanova.webp',NULL,'@ksenia_start_vk','+79990000016','2026-06-14 11:56:25','2026-06-14 11:56:25'),(25,34,'Игорь Устинов','Силовая выносливость',12,41,'Сочетает силовую выносливость, общефизическую подготовку и грамотную периодизацию нагрузок. Подходит для долгосрочного прогресса.','/seed-images/trainers/igor-ustinov.webp',NULL,'@igor_power_vk','+79990000017','2026-06-14 11:56:25','2026-06-14 11:56:25');
/*!40000 ALTER TABLE `trainers` ENABLE KEYS */;
UNLOCK TABLES;

