INSERT INTO `workouts` VALUES (1,1,1,1,42,1,0,'Неделя 1: Техника движения','Разминка суставов, присед к опоре, тяга резинки, отжимания от возвышения и планка. Главная задача — почувствовать безопасные амплитуды. Фокус недели: Осваиваем присед, наклон, жим и тягу в спокойном темпе.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(2,1,1,2,46,2,0,'Неделя 1: Круг на всё тело','Низкоударный круг: выпады назад, тяга, жим, ягодичный мост и фермерская прогулка. Работайте умеренно, сохраняя разговорный темп. Фокус недели: Осваиваем присед, наклон, жим и тягу в спокойном темпе.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(3,1,1,3,38,3,0,'Неделя 1: Кор и восстановление','Дыхание, стабилизация корпуса, боковая планка, dead bug и мягкая растяжка бёдер. Тренировка закрепляет контроль тела. Фокус недели: Осваиваем присед, наклон, жим и тягу в спокойном темпе.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(4,1,2,1,44,4,0,'Неделя 2: Техника движения','Разминка суставов, присед к опоре, тяга резинки, отжимания от возвышения и планка. Главная задача — почувствовать безопасные амплитуды. Фокус недели: Добавляем круговой формат и учимся держать пульс под контролем.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(5,1,2,2,48,5,0,'Неделя 2: Круг на всё тело','Низкоударный круг: выпады назад, тяга, жим, ягодичный мост и фермерская прогулка. Работайте умеренно, сохраняя разговорный темп. Фокус недели: Добавляем круговой формат и учимся держать пульс под контролем.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(6,1,2,3,40,6,0,'Неделя 2: Кор и восстановление','Дыхание, стабилизация корпуса, боковая планка, dead bug и мягкая растяжка бёдер. Тренировка закрепляет контроль тела. Фокус недели: Добавляем круговой формат и учимся держать пульс под контролем.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(7,1,3,1,46,7,0,'Неделя 3: Техника движения','Разминка суставов, присед к опоре, тяга резинки, отжимания от возвышения и планка. Главная задача — почувствовать безопасные амплитуды. Фокус недели: Увеличиваем плотность работы без потери техники.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(8,1,3,2,50,8,0,'Неделя 3: Круг на всё тело','Низкоударный круг: выпады назад, тяга, жим, ягодичный мост и фермерская прогулка. Работайте умеренно, сохраняя разговорный темп. Фокус недели: Увеличиваем плотность работы без потери техники.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(9,1,3,3,42,9,0,'Неделя 3: Кор и восстановление','Дыхание, стабилизация корпуса, боковая планка, dead bug и мягкая растяжка бёдер. Тренировка закрепляет контроль тела. Фокус недели: Увеличиваем плотность работы без потери техники.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(10,1,4,1,48,10,0,'Неделя 4: Техника движения','Разминка суставов, присед к опоре, тяга резинки, отжимания от возвышения и планка. Главная задача — почувствовать безопасные амплитуды. Фокус недели: Собираем цельную тренировку и фиксируем личный прогресс.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(11,1,4,2,52,11,0,'Неделя 4: Круг на всё тело','Низкоударный круг: выпады назад, тяга, жим, ягодичный мост и фермерская прогулка. Работайте умеренно, сохраняя разговорный темп. Фокус недели: Собираем цельную тренировку и фиксируем личный прогресс.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(12,1,4,3,44,12,0,'Неделя 4: Кор и восстановление','Дыхание, стабилизация корпуса, боковая планка, dead bug и мягкая растяжка бёдер. Тренировка закрепляет контроль тела. Фокус недели: Собираем цельную тренировку и фиксируем личный прогресс.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(13,2,1,1,58,1,0,'Неделя 1: Ноги и базовая сила','Присед или жим ногами, румынская тяга, выпады, икры и антискручивания. Вес растёт только при стабильной технике. Фокус недели: Находим рабочие веса и повторяем технику базовых движений.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(14,2,1,2,56,2,0,'Неделя 1: Верх тела: жим и тяга','Жим гантелей, горизонтальная тяга, вертикальная тяга, плечи и разгибания. Следите за положением лопаток и ровным темпом. Фокус недели: Находим рабочие веса и повторяем технику базовых движений.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(15,2,1,3,50,3,0,'Неделя 1: Силовая выносливость','Умеренный круг из тяг, толчковых движений, переносок и кора. Цель — выдерживать качество под усталостью. Фокус недели: Находим рабочие веса и повторяем технику базовых движений.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(16,2,2,1,60,4,0,'Неделя 2: Ноги и базовая сила','Присед или жим ногами, румынская тяга, выпады, икры и антискручивания. Вес растёт только при стабильной технике. Фокус недели: Увеличиваем объём подходов на ноги и спину.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(17,2,2,2,58,5,0,'Неделя 2: Верх тела: жим и тяга','Жим гантелей, горизонтальная тяга, вертикальная тяга, плечи и разгибания. Следите за положением лопаток и ровным темпом. Фокус недели: Увеличиваем объём подходов на ноги и спину.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(18,2,2,3,52,6,0,'Неделя 2: Силовая выносливость','Умеренный круг из тяг, толчковых движений, переносок и кора. Цель — выдерживать качество под усталостью. Фокус недели: Увеличиваем объём подходов на ноги и спину.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(19,2,3,1,62,7,0,'Неделя 3: Ноги и базовая сила','Присед или жим ногами, румынская тяга, выпады, икры и антискручивания. Вес растёт только при стабильной технике. Фокус недели: Добавляем темповые повторения и паузы в нижней точке.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(20,2,3,2,60,8,0,'Неделя 3: Верх тела: жим и тяга','Жим гантелей, горизонтальная тяга, вертикальная тяга, плечи и разгибания. Следите за положением лопаток и ровным темпом. Фокус недели: Добавляем темповые повторения и паузы в нижней точке.',NULL,'2026-06-14 08:07:11','2026-06-14 08:07:11'),(21,2,3,3,54,9,0,'Неделя 3: Силовая выносливость','Умеренный круг из тяг, толчковых движений, переносок и кора. Цель — выдерживать качество под устал